+  // access dest. We rely on AA with CapturesBeforeAnalysis to figure this out.
+  {
+    MemoryLocation DestWithSrcSize(cpyDest, LocationSize::precise(srcSize));
+    CapturesBeforeAnalysis CBA(*DT);
