+    BatchAAResults BAAWithCCA(*AA, &CCA);
+    if (isModOrRefSet(BAAWithCCA.getModRefInfo(C, DestWithSrcSize)))
+      return false;
+  }

   // We can't create address space casts here because we don't know if they're
   // safe for the target.
